// Import the Workbox libraries generated by next-pwa.
import { precacheAndRoute } from 'workbox-precaching';
import { registerRoute } from 'workbox-routing';
import { StaleWhileRevalidate } from 'workbox-strategies';

// This is the injection point for the manifest generated by next-pwa.
// It contains a list of all assets to be cached.
precacheAndRoute(self.__WB_MANIFEST);

// Example of a custom caching strategy for API calls (optional).
registerRoute(
  ({ url }) => url.pathname.startsWith('/api/'),
  new StaleWhileRevalidate({
    cacheName: 'api-cache',
  })
);

// --- FIREBASE MESSAGING SERVICE WORKER LOGIC ---
// This part must be included to handle push notifications.
self.addEventListener('push', (event) => {
  console.log('Push event received:', event);
  const data = event.data?.json() ?? {};
  const title = data.notification?.title || 'Notificación';
  const options = {
    body: data.notification?.body || 'Tienes una nueva notificación.',
    icon: data.notification?.icon || '/icons/icon-192x192.png',
    data: {
      url: data.fcmOptions?.link || '/',
    },
  };
  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const urlToOpen = event.notification.data.url;
  event.waitUntil(
    self.clients.openWindow(urlToOpen)
  );
});

// Import and initialize Firebase.
// This part is crucial and now integrated directly.
importScripts('https://www.gstatic.com/firebasejs/9.23.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/9.23.0/firebase-messaging-compat.js');

const firebaseConfig = {
  apiKey: "AIzaSyCwH29ruiIl_pohEoUHh7d26m5qCLCmYm0",
  authDomain: "wikistars5-2yctr.firebaseapp.com",
  projectId: "wikistars5-2yctr",
  storageBucket: "wikistars5-2yctr.appspot.com",
  messagingSenderId: "939359993461",
  appId: "1:939359993461:web:c8aab67046db949495823c",
  measurementId: "G-XCFCPXNP56"
};

firebase.initializeApp(firebaseConfig);

try {
  const messaging = firebase.messaging();
  // Optional: Set a background message handler.
  messaging.onBackgroundMessage((payload) => {
    console.log('[service-worker.js] Received background message ', payload);
    const notificationTitle = payload.notification.title;
    const notificationOptions = {
      body: payload.notification.body,
      icon: payload.notification.icon,
    };
    self.registration.showNotification(notificationTitle, notificationOptions);
  });
} catch(e) {
  console.error('[service-worker.js] Firebase messaging initialization failed', e);
}
